"""HLD Core Concepts: Sharding, Consistent Hashing, CAP Theorem, Numbers to Know — 20 MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def sharding_lesson() -> Lesson:
    return Lesson(id="hld-sharding", number=105, title="Sharding",
        focus=("shard keys","range vs hash","hotspots","rebalancing","cross-shard queries"),
        overview="Sharding is how you scale databases horizontally. The shard key choice makes or breaks the design.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("sh-1","What is database sharding?","easy",("sharding",),("Backing up data","Splitting a database across multiple machines, each holding a subset of data","Replicating data","Indexing"),1,"Sharding distributes rows across nodes so no single machine handles all traffic."),
        quiz("sh-2","What makes a good shard key?","hard",("sharding",),("The PK always","High cardinality, even distribution, frequently used in queries, rarely changing","Any random column","The timestamp"),1,"A good shard key distributes data evenly and supports common query patterns."),
        quiz("sh-3","What is a hot shard?","hard",("sharding",),("A shard with latest data","A shard receiving disproportionate traffic due to poor key distribution","A full shard","A slow replica"),1,"Hot shards occur when a key value is too popular. Fix: composite keys, salting, range splitting."),
        quiz("sh-4","Range-based vs hash-based sharding?","medium",("sharding",),("Identical","Range assigns key ranges (good for scans); hash assigns by hash (good for distribution)","Hash is always better","Range doesn't work with strings"),1,"Range supports range queries but risks hotspots. Hash distributes evenly but makes range queries expensive."),
        quiz("sh-5","What is a cross-shard query?","hard",("sharding",),("A single-shard query","A query needing data from multiple shards, requiring scatter-gather and coordination","A backup query","A cached query"),1,"Cross-shard queries fan out to multiple nodes and require merging. Very expensive."),
        quiz("sh-6","What is shard rebalancing?","medium",("sharding",),("Deleting old data","Moving data between shards when load becomes uneven or shards are added/removed","Creating replicas","Backing up"),1,"Rebalancing redistributes data — expensive, must be done carefully to avoid downtime."),
        quiz("sh-7","Why is auto-increment ID bad as a shard key?","hard",("sharding",),("Too long","Sequential IDs route all new writes to the same shard, creating a hotspot","Not unique","Too much memory"),1,"Sequential keys concentrate recent writes. Use UUIDs, Snowflake IDs, or hash-based assignment."),
        quiz("sh-8","What is directory-based sharding?","medium",("sharding",),("Sharding by filename","A central service maps each key to its shard, allowing flexible placement at extra hop cost","A hash function","A replication strategy"),1,"Directory-based offers maximum flexibility but the directory becomes a SPOF."),
        quiz("sh-9","How does sharding affect JOINs?","hard",("sharding",),("No effect","JOINs across shards become very expensive or impossible — denormalize or co-locate","JOINs become faster","Enables new JOIN types"),1,"Fundamental tradeoff: sharding sacrifices JOIN capability."),
        quiz("sh-10","What is geo-sharding?","medium",("sharding",),("Sharding by data type","Partitioning data by geographic region so users' data is stored near them","A CDN feature","Sharding by timestamp"),1,"Geo-sharding reduces latency and helps with data residency regulations (GDPR)."),
        quiz("sh-11","What is scatter-gather?","hard",("sharding",),("A caching pattern","Send query to all shards (scatter), collect results, merge and return (gather)","A replication pattern","A LB technique"),1,"Scatter-gather is necessary when the shard key isn't in the query."),
        quiz("sh-12","Sharding vs partitioning — what's the difference?","medium",("sharding",),("Completely different","Partitioning is general concept; sharding distributes partitions across different machines","Sharding is NoSQL only","Partitioning is for reads only"),1,"A single PostgreSQL can have partitions (one machine). Sharding distributes across nodes."),
        quiz("sh-13","How does Instagram generate sharded IDs?","hard",("sharding",),("Auto-increment","Snowflake-like: timestamp + shard ID + sequence number — unique, sortable, shard-aware","UUIDs","Random numbers"),1,"41 bits timestamp + 13 bits shard ID + 10 bits sequence = globally unique, chronologically sortable."),
        quiz("sh-14","What is data co-location in sharding?","medium",("sharding",),("Storing all on one server","Placing related data on the same shard to enable efficient local JOINs and transactions","A backup strategy","A CDN technique"),1,"Co-location avoids cross-shard operations. Example: shard by user_id for all user data."),
        quiz("sh-15","What happens to transactions in a sharded DB?","hard",("sharding",),("Work the same","Single-shard transactions work; cross-shard require 2PC or Saga patterns","Not supported","They become faster"),1,"Cross-shard transactions are expensive (2PC) or must be redesigned as eventual consistency workflows."),
        quiz("sh-16","What is resharding?","hard",("sharding",),("Adding indexes","Changing the sharding scheme, requiring massive data migration with minimal downtime","Removing shards","Adding replicas"),1,"Resharding is painful. Plan your shard key carefully upfront to avoid it."),
        quiz("sh-17","For a social network, why shard by user_id?","hard",("sharding",),("User IDs are smaller","Most queries are user-centric (my feed, posts) so co-locating user data avoids cross-shard queries","Post IDs have hotspots","User IDs are sequential"),1,"User-centric access patterns dominate social networks."),
        quiz("sh-18","What is the challenge of unique constraints across shards?","hard",("sharding",),("No challenge","Each shard only sees its data; global uniqueness requires centralized check or clever key design","Unique constraints are auto","Shards share indexes"),1,"Options: Snowflake IDs, centralized uniqueness service, or inherently unique key design."),
        quiz("sh-19","What is virtual sharding?","hard",("sharding",),("Cloud sharding","Each physical node owns multiple virtual positions on the hash ring for better load distribution","A simulation","Sharding without DB"),1,"Virtual nodes improve balance in consistent hashing by giving each node multiple ring positions."),
        quiz("sh-20","What is a shard proxy?","medium",("sharding",),("A database index","A routing layer that directs queries to the correct shard based on the shard key","A caching layer","A load balancer"),1,"Shard proxies (e.g., Vitess for MySQL) handle routing, connection pooling, and query rewriting."),
    ))

def consistent_hashing_lesson() -> Lesson:
    return Lesson(id="hld-consistent-hashing", number=106, title="Consistent Hashing",
        focus=("hash ring","virtual nodes","rebalancing","load distribution","key mapping"),
        overview="Consistent hashing minimizes key redistribution when nodes are added/removed. Essential for distributed caches and databases.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("ch-1","What problem does consistent hashing solve?","medium",("consistent-hashing",),("Encryption","When nodes are added/removed, only a small fraction of keys need remapping (vs modulo remapping all)","Sorting data","Compression"),1,"With modulo hashing, adding a node remaps almost all keys. Consistent hashing remaps only ~1/N."),
        quiz("ch-2","How does a consistent hash ring work?","medium",("consistent-hashing",),("A linked list","Nodes and keys are hashed onto a circular ring; each key is assigned to the first node clockwise from it","A tree structure","A hash table"),1,"The ring is [0, 2^32). Hash both node IPs and keys. Walk clockwise from key's position to find its node."),
        quiz("ch-3","What are virtual nodes (vnodes)?","hard",("consistent-hashing",),("Cloud VMs","Each physical node maps to multiple positions on the hash ring for better load distribution","Virtual machines","Simulated nodes"),1,"Without vnodes, nodes with different capacities or unlucky hash positions get uneven load."),
        quiz("ch-4","How many virtual nodes per physical node is typical?","hard",("consistent-hashing",),("1","100-200 vnodes per physical node for good distribution","1000","10"),1,"More vnodes = smoother distribution. Cassandra defaults to 256 tokens per node."),
        quiz("ch-5","What happens when a node is added to the ring?","medium",("consistent-hashing",),("All keys remapped","Only keys between the new node and its predecessor are moved to the new node","Nothing changes","All nodes rebalance"),1,"Only ~1/N keys move on average. This is the key advantage over modulo hashing."),
        quiz("ch-6","What happens when a node is removed?","medium",("consistent-hashing",),("All data lost","Its keys are reassigned to the next node clockwise on the ring","Ring collapses","All keys remapped"),1,"Only the failed node's keys move. All other assignments remain stable."),
        quiz("ch-7","Why does modulo hashing (key % N) fail when N changes?","medium",("consistent-hashing",),("It doesn't fail","Changing N (nodes) remaps almost every key to a different node, causing massive cache misses","Modulo is slower","Modulo doesn't distribute evenly"),1,"Going from 3→4 nodes: 2/3 of keys remap. Consistent hashing: only 1/4."),
        quiz("ch-8","Which systems use consistent hashing?","medium",("consistent-hashing",),("Only caches","DynamoDB, Cassandra, Memcached, CDNs, and distributed caches","Only databases","Only load balancers"),1,"It's fundamental to any distributed system that partitions data across nodes."),
        quiz("ch-9","How does consistent hashing relate to replication?","hard",("consistent-hashing",),("It doesn't","Keys can be replicated to the next N nodes clockwise on the ring for fault tolerance","Replication replaces hashing","Hashing prevents replication"),1,"DynamoDB replicates each key to 3 nodes clockwise on the ring (preferring distinct physical nodes)."),
        quiz("ch-10","What is the load balancing challenge with consistent hashing?","hard",("consistent-hashing",),("No challenge","Without virtual nodes, nodes can get very uneven loads due to random hash distribution","It's too slow","It uses too much memory"),1,"With K physical nodes and no vnodes, standard deviation of load is O(1/√K) — too high for small K."),
        quiz("ch-11","How does DynamoDB use consistent hashing?","hard",("consistent-hashing",),("It doesn't","Partitions data across storage nodes with virtual nodes and preference lists for replication","Uses range sharding only","Uses modulo hashing"),1,"DynamoDB's consistent hashing with vnodes and coordinator-based routing. Described in the Dynamo paper."),
        quiz("ch-12","What is a preference list in DynamoDB's consistent hashing?","hard",("consistent-hashing",),("A user preference","The ordered list of nodes responsible for storing replicas of a key, skipping same-rack nodes","A query optimization","A caching strategy"),1,"The preference list ensures replicas land on distinct physical nodes for fault tolerance."),
        quiz("ch-13","How does consistent hashing handle heterogeneous nodes?","hard",("consistent-hashing",),("It can't","Assign more virtual nodes to higher-capacity machines so they handle proportionally more keys","Use same-size nodes only","Use separate rings"),1,"A 2x capacity node gets 2x vnodes, receiving roughly 2x the traffic."),
        quiz("ch-14","What is jump consistent hash?","hard",("consistent-hashing",),("A ring-based hash","A hash algorithm that maps keys to buckets uniformly with O(ln n) time and no ring overhead","A binary search","A modulo variant"),1,"Jump hash is simpler and more uniform than ring-based consistent hashing, but only supports sequential bucket IDs."),
        quiz("ch-15","What is rendezvous (highest random weight) hashing?","hard",("consistent-hashing",),("A load balancing algorithm","Each key computes a score for each node; the highest-scoring node wins — no ring needed","A tree structure","A caching strategy"),1,"Rendezvous hashing: simpler conceptually but O(N) per lookup. Good for small N."),
        quiz("ch-16","How does Cassandra use consistent hashing?","hard",("consistent-hashing",),("It doesn't","Each node owns token ranges on the ring; data is placed based on partition key hash","Uses modulo hashing","Uses range-based only"),1,"Cassandra uses Murmur3 hash of the partition key to place data on the ring."),
        quiz("ch-17","What is the impact of consistent hashing on cache hit rates during scaling?","hard",("consistent-hashing",),("No impact","Adding a node causes only ~1/N cache misses instead of near-total cache invalidation","100% cache miss","50% cache miss"),1,"This is why CDNs and distributed caches use consistent hashing — scaling doesn't destroy cache."),
        quiz("ch-18","How does consistent hashing handle rack/zone awareness?","hard",("consistent-hashing",),("It doesn't","Skip vnodes in the same rack when building replica sets to ensure fault tolerance across failure domains","Only one rack is used","Racks are irrelevant"),1,"Network topology-aware placement ensures replicas survive rack/zone failures."),
        quiz("ch-19","What is bounded load consistent hashing?","hard",("consistent-hashing",),("Load limiting","Variant where each node has a max load cap — if a node is overloaded, keys spill to the next node","A rate limiter","A firewall rule"),1,"Google's bounded load variant prevents hotspots by redistributing overflow keys."),
        quiz("ch-20","What is the relationship between consistent hashing and DHTs?","hard",("consistent-hashing",),("None","DHTs (Chord, Kademlia) use consistent hashing as the foundation for decentralized key-value lookup","DHTs replace hashing","Hashing replaces DHTs"),1,"DHTs extend consistent hashing with routing tables for O(log N) lookups in peer-to-peer systems."),
    ))

def cap_theorem_lesson() -> Lesson:
    return Lesson(id="hld-cap-theorem", number=107, title="CAP Theorem",
        focus=("consistency","availability","partition tolerance","PACELC","quorum","split-brain"),
        overview="CAP theorem drives database selection in every system design interview. Know it deeply.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("cap-1","What does CAP theorem actually state?","medium",("cap",),("Pick all three","During a network partition, you must choose between Consistency and Availability","CPU, Availability, Performance","Only applies to SQL"),1,"During a partition (P), choose CP or AP. You can't have both C and A simultaneously."),
        quiz("cap-2","Is DynamoDB CP or AP?","hard",("cap",),("CP","AP by default (eventually consistent reads), with optional strongly consistent reads","Neither","Both"),1,"DynamoDB defaults to eventually consistent (AP) but offers strongly consistent at higher cost."),
        quiz("cap-3","Is PostgreSQL CP or AP?","medium",("cap",),("AP","CP — prioritizes consistency over availability during partitions","Neither","Depends on version"),1,"Traditional RDBMS are CP: reject writes rather than risk inconsistency."),
        quiz("cap-4","What does PACELC add to CAP?","hard",("cap",),("Nothing","When no partition (Else), you still choose between Latency and Consistency","Replaces CAP","Adds Performance"),1,"PACELC: if Partition → A or C. Else → L(atency) or C(onsistency). More nuanced."),
        quiz("cap-5","What is the quorum formula?","hard",("cap",),("N/2","W + R > N ensures overlap between write and read sets","N - 1","Always N"),1,"For N=3: W=2, R=2 guarantees reading latest write. W+R=4 > 3."),
        quiz("cap-6","What is split-brain?","hard",("cap",),("A database error","When a partition causes two cluster halves to each believe they are leader, causing conflicting writes","A caching issue","A LB failure"),1,"Split-brain can cause data corruption. Solutions: quorum leader election, fencing tokens, STONITH."),
        quiz("cap-7","What is a vector clock?","hard",("cap",),("A physical clock","A logical clock tracking causality across nodes using per-node counters","A timestamp format","A LB algorithm"),1,"Vector clocks detect causality and concurrency in distributed systems without synchronized clocks."),
        quiz("cap-8","What is Cassandra's consistency model?","hard",("cap",),("Always strong","Tunable — choose consistency per query (ONE, QUORUM, ALL)","Eventually consistent only","Same as PostgreSQL"),1,"Cassandra lets you choose: ONE (fast, stale) to ALL (slow, consistent)."),
        quiz("cap-9","What is the two-generals problem?","hard",("cap",),("A scheduling problem","It's impossible to guarantee agreement between two parties over an unreliable network","A LB issue","A caching problem"),1,"Proves consensus over unreliable networks is impossible — foundational to distributed systems."),
        quiz("cap-10","What is linearizability?","hard",("cap",),("Same as serializability","The strongest consistency: operations appear to execute atomically at some point between invocation and response","A weak consistency","Only for SQL"),1,"Linearizability provides real-time ordering guarantees. Expensive but sometimes necessary."),
        quiz("cap-11","What is causal consistency?","hard",("cap",),("Same as eventual","Operations that are causally related are seen in the same order by all nodes","The strongest model","Only for NoSQL"),1,"Weaker than linearizability but stronger than eventual. Preserves happens-before relationships."),
        quiz("cap-12","What is read-your-own-writes consistency?","medium",("cap",),("Always consistent","A user always sees their own most recent writes, even if other users see stale data","A caching strategy","A replication mode"),1,"Achieved by routing reads to the leader or to a replica that has caught up with the user's last write."),
        quiz("cap-13","What is monotonic read consistency?","hard",("cap",),("Reads get faster","Once you read a value, you never see an older value in subsequent reads","Reads are ordered","A write guarantee"),1,"Without this, reading from different replicas could show time-traveling data."),
        quiz("cap-14","What is the Raft consensus algorithm?","hard",("cap",),("A load balancer","A leader-based consensus protocol: leader election, log replication, safety guarantees","A hash algorithm","A sharding strategy"),1,"Raft is simpler than Paxos. Used by etcd, CockroachDB, TiKV for distributed consensus."),
        quiz("cap-15","What is a lease in distributed systems?","hard",("cap",),("A rental agreement","A time-bounded lock that automatically expires, preventing indefinite lock holding","A connection","A session"),1,"Leases prevent zombie leaders from making changes after being replaced."),
        quiz("cap-16","What is a fencing token?","hard",("cap",),("A security token","A monotonically increasing token given with each lock grant to detect stale lock holders","A JWT","An API key"),1,"Fencing tokens prevent split-brain: storage rejects writes with tokens lower than the latest seen."),
        quiz("cap-17","What is the difference between CP and AP systems in practice?","medium",("cap",),("Only theoretical","CP systems (ZooKeeper, PostgreSQL) reject requests during partitions; AP systems (DynamoDB, Cassandra) serve stale data","AP is always better","CP is always faster"),1,"The choice depends on your application: banking needs CP; social feeds can tolerate AP."),
        quiz("cap-18","What is tunable consistency?","hard",("cap",),("Fixed consistency","Ability to choose consistency level per operation (e.g., Cassandra's ONE, QUORUM, ALL)","A database feature","An API setting"),1,"Tunable consistency lets you trade latency for freshness on a per-query basis."),
        quiz("cap-19","What is the gossip protocol?","hard",("cap",),("A consensus algorithm","A peer-to-peer protocol where nodes periodically exchange state information","A query protocol","A replication mechanism"),1,"Gossip propagates cluster state (membership, health) without a central coordinator. Eventually consistent."),
        quiz("cap-20","What is anti-entropy in distributed systems?","hard",("cap",),("Data corruption","A background process that compares data across replicas and repairs inconsistencies","A caching strategy","An encryption technique"),1,"Anti-entropy (e.g., Merkle tree comparison) ensures replicas converge even after network issues."),
    ))

def numbers_lesson() -> Lesson:
    return Lesson(id="hld-numbers", number=108, title="Numbers to Know",
        focus=("latency","throughput","storage","back-of-envelope","Little's Law"),
        overview="The numbers let you estimate capacity, justify design choices, and show interviewers you think quantitatively.",
        patterns=(), badge="HLD Core", tasks=(
        quiz("num-1","What is the approximate latency of a same-datacenter round-trip?","medium",("numbers",),("1 ns","0.5 ms","50 ms","500 ms"),1,"Intra-DC: ~0.5ms. Cross-continent: ~100-150ms."),
        quiz("num-2","How many QPS can a single modern server handle for simple API requests?","medium",("numbers",),("100","1,000","10,000-50,000","1 million"),2,"A well-optimized server handles 10K-50K simple API req/sec."),
        quiz("num-3","What is the approximate sequential read speed of an SSD?","medium",("numbers",),("1 MB/s","50 MB/s","500 MB/s - 3 GB/s","100 GB/s"),2,"Modern NVMe SSDs: 500MB/s to 3GB/s sequential. Random reads are slower."),
        quiz("num-4","How much data can a single PostgreSQL handle well?","hard",("numbers",),("1 GB","A few hundred GB to low TB range","100 TB","1 PB"),1,"PostgreSQL works well up to a few hundred GB to low terabytes."),
        quiz("num-5","1 billion users × 1 KB each = ?","easy",("numbers",),("1 GB","100 GB","1 TB","1 PB"),2,"1B × 1KB = 1TB. A common back-of-envelope calculation."),
        quiz("num-6","What is the approximate latency of reading 1 MB from memory?","hard",("numbers",),("1 ns","250 μs (0.25 ms)","10 ms","100 ms"),1,"Memory: ~250μs/MB. SSD: ~1ms. HDD: ~20ms."),
        quiz("num-7","If a service handles 10K req/s at 100ms each, how many concurrent connections?","medium",("numbers",),("100","1,000","10,000","100,000"),1,"Little's Law: Concurrency = Throughput × Latency = 10K × 0.1s = 1,000."),
        quiz("num-8","What is the cost ratio of RAM to SSD per GB?","medium",("numbers",),("Same cost","RAM is ~30-50x more expensive","SSD is more expensive","RAM is 2x more"),1,"RAM: ~$5-10/GB. SSD: ~$0.10-0.25/GB. Drives caching and storage tier decisions."),
        quiz("num-9","How many bytes per second does a 1 Gbps link provide?","medium",("numbers",),("1 GB/s","~125 MB/s","1 MB/s","10 GB/s"),1,"1Gbps ÷ 8 = 125 MB/s. Real throughput slightly less due to overhead."),
        quiz("num-10","What does 99.999% (5 nines) availability mean in annual downtime?","medium",("numbers",),("~5 minutes/year","~5 hours/year","~1 hour/year","~52 minutes/year"),0,"99.999%=5.26min/yr. 99.99%=52.6min/yr. 99.9%=8.76hr/yr."),
        quiz("num-11","How many bytes in a UUID?","medium",("numbers",),("4","8","16","32"),2,"UUID = 128 bits = 16 bytes. As hex string with dashes: 36 characters."),
        quiz("num-12","What is the typical write throughput of a single HDD?","medium",("numbers",),("1 MB/s","100 MB/s sequential, 1-2 MB/s random","1 GB/s","10 GB/s"),1,"HDDs: ~100MB/s sequential but only 100-200 IOPS random. SSDs: 100K+ IOPS."),
        quiz("num-13","How many daily active users can a single server handle?","medium",("numbers",),("100","10,000","1-10 million (depends on workload)","1 billion"),2,"Varies hugely by workload, but millions of DAU with proper architecture is feasible."),
        quiz("num-14","What is the typical latency of a DNS lookup?","medium",("numbers",),("1 ns","1-100 ms","1 second","10 seconds"),1,"Cached DNS: ~1ms. Uncached with recursive resolution: 20-100ms."),
        quiz("num-15","How much storage does 1 million tweets (280 chars each) need?","medium",("numbers",),("28 MB","280 MB","2.8 GB","28 GB"),1,"1M × 280 bytes ≈ 280 MB. With metadata (user, timestamp, etc.): ~1-2GB."),
        quiz("num-16","What is the typical compression ratio for text data?","medium",("numbers",),("1:1 (no compression)","3:1 to 10:1 depending on data","100:1","1000:1"),1,"gzip typically achieves 3-5x on text, 10x on repetitive data like logs."),
        quiz("num-17","What is Little's Law?","hard",("numbers",),("A database rule","L = λ × W (average items = arrival rate × avg time in system)","A caching formula","An indexing theorem"),1,"Little's Law: concurrent requests = throughput × latency. Fundamental for capacity planning."),
        quiz("num-18","How many TCP connections can a single server maintain?","hard",("numbers",),("1,000","10,000","100K-1M with proper OS tuning","10 million"),2,"Each connection needs a file descriptor and some memory. With epoll and tuning, 1M+ is achievable."),
        quiz("num-19","What is the typical size of a database row in a social media app?","medium",("numbers",),("1 byte","1 KB","1 MB","1 GB"),1,"A typical row (user profile, post, etc.) is 0.5-2KB including all columns."),
        quiz("num-20","If you need 99.99% availability across 3 independent services in series, what availability does each need?","hard",("numbers",),("99.99%","99.997% each (since 0.99997³ ≈ 0.9999)","99.9%","100%"),1,"Services in series multiply: for 99.99% overall, each service needs ~99.997% availability."),
    ))
